    title: "\u041f\u0440\u043e\u0444\u0438\u043b\u0430\u043a\u0442\u0438\u043a\u0430 \u0442\u0440\u0430\u0432\u043c\u0430\u0442\u0438\u0437\u043c\u0430",
    content: "<p className=\"text-justify mb-4\"><a href=\"/profilaktika-tramatizma\" target=\"_blank\" rel=\"noopener noreferrer\">\u041f\u0435\u0440\u0435\u0439\u0442\u0438&nbsp;</a></p>",
